            switch (raycastMode)
            {
                case RaycastMode.Camera:
                    // Camera line.
                    Gizmos.color = Color.green;
                    PointerRay pointerRay = CalculateRay(this, RaycastMode.Camera);
                    Gizmos.DrawLine(pointerRay.ray.origin,
